    for (int i = 1; i <= 5; i++) {
        cout << i << " ";
    }
    cout << endl;
    return 0;
}

#include <iostream>
using namespace std;

int sum(int a, int b) {
    return a + b;
}

int main() {
    cout << sum(3, 7) << endl;
    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int arr[5] = {1, 2, 3, 4, 5};
    int sum = 0;
    for (int i = 0; i < 5; i++) {
        sum += arr[i];
    }
    cout << sum << endl;
    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int x = 10;
    int* ptr = &x;
    cout << *ptr << endl;
    return 0;
}

#include <iostream>
using namespace std;

class Person {
public:
    string name;
    int age;
    Person(string n, int a) : name(n), age(a) {}
};

int main() {
    Person p("John", 25);
    cout << p.name << " " << p.age << endl;
    return 0;
}

#include <iostream>
#include <vector>
using namespace std;

int main() {
    vector<int> v = {1, 2, 3};
    v.push_back(4);
    v.push_back(5);
    int sum = 0;
    for (int x : v) sum += x;
    cout << v.size() << endl << sum << endl;
    return 0;
}

#include <iostream>
using namespace std;

template <typename T>
T maxVal(T a, T b) {
    return a > b ? a : b;
}

int main() {
    cout << maxVal(5, 3) << endl;
    return 0;
}

#include <iostream>
using namespace std;

class Animal {
public:
    virtual void sound() { cout << "Sound" << endl; }
};

class Dog : public Animal {
public:
    void sound() override { cout << "Bark" << endl; }
};

int main() {
    Dog d;
    d.sound();
    return 0;
}
